import json
import re

with open(locals()['var_function-call-16632172874857875208'], 'r') as f:
    docs = json.load(f)
with open(locals()['var_function-call-9730938913871448610'], 'r') as f:
    citations = json.load(f)

citation_map = {rec['title']: int(rec['citation_count']) for rec in citations}
relevant_docs = [d for d in docs if d['filename'].replace('.txt', '') in citation_map]

print(f"Relevant docs count: {len(relevant_docs)}")

venues = {}
for doc in relevant_docs:
    text = doc['text'][:5000]
    venue = "Unknown"
    if re.search(r"UbiComp", text, re.IGNORECASE):
        venue = "UbiComp"
    elif re.search(r"CSCW", text, re.IGNORECASE):
        venue = "CSCW"
    elif re.search(r"DIS", text, re.IGNORECASE):
        venue = "DIS"
    elif re.search(r"OZCHI", text, re.IGNORECASE):
        venue = "OZCHI"
    elif re.search(r"IUI", text, re.IGNORECASE):
        venue = "IUI"
    elif re.search(r"MobileHCI", text, re.IGNORECASE):
        venue = "MobileHCI"
    elif re.search(r"TEI", text, re.IGNORECASE):
        venue = "TEI"
    elif re.search(r"CHI", text, re.IGNORECASE):
        # We already know they contain CHI (from query). But maybe it's "CHI 2015"?
        # Let's check strict CHI again
        p1 = r"(?:^|[^a-zA-Z0-9])CHI\s+(?:'?\d{2}|20\d{2})"
        if re.search(p1, text, re.IGNORECASE):
            venue = "CHI"
        else:
            venue = "CHI_Mention_Only"

    venues[doc['filename']] = venue

result = {
    "count": len(relevant_docs),
    "venues_summary": venues
}

print("__RESULT__:")
print(json.dumps(result))

